import React, { useState } from 'react';
import { jsPDF } from 'jspdf';
import html2canvas from 'html2canvas';

const CreateInvoice = ( {services, onClose} ) => {
    const [patientName, setPatientName] = useState('');
    const [selectedServices, setSelectedServices] = useState<{ id: number; name: string; description: string; quantity: string; price: number}[]>([]);
    const [totalAmount, setTotalAmount] = useState(0);

    const handleSelectService = (e) => {
        const serviceID = parseInt(e.target.value);
        const selectedService = services.find((service) => service.id == serviceID)

        if (selectedService) {
            setSelectedServices((prev) => [...prev, {...selectedService, quantity: 1}])
            setTotalAmount((prev) => prev + (selectedService.price || 0))
        }

    };

    const handleRemoveService = (index) => {
        const removedService = selectedServices[index];
        setSelectedServices((prev) => prev.filter((_,i) => i !== index))
        setTotalAmount((prev) => prev - (removedService.price || 0))

    };

    const handleChangeQuantity = (e) => {
        const newQuantity = e.target.value;
        const prevQuantity = pa
    }

    const generateInvoice = async () => {
        const invoiceElement = document.getElementById('invoice');
        if (invoiceElement) {
            const canvas = await html2canvas(invoiceElement);
            const imgData = canvas.toDataURL('image/png');
            const pdf = new jsPDF('p','mm', 'a4');
            pdf.addImage(imgData, 'PNG', 0, 0, 210, canvas.height * (210/canvas.width));
            pdf.save(`Invoice_${patientName}.pdf`)
        }

    };

    return(
        <div>
            <h2>Create Invoice</h2>
            <button className='close-button' onClick={onClose}>X</button>
            <form>
                <input 
                    type ='text' 
                    placeholder='Patient Name'
                    value={patientName}
                    onChange={(e) => setPatientName(e.target.value)}/>
                <select onChange={handleSelectService} defaultValue=''>
                    <option value='' disabled>
                        Select a Service
                    </option>
                    {services.map((service)=>(
                        <option key={service.id} value={service.id}>
                            {service.name} : ${service.price}
                        </option>
                ))}
                </select>
                <ul>
                    {selectedServices.map((service, index) => (
                        <li key = {index}>
                            {service.name}: ${service.price}
                            <input
                            type ='number'
                            min = '1'
                            value={service.quantity}
                            onChange={(e) => setPatientName(e.target.value)}/>
                            <button type='button' onClick={handleRemoveService}>Remove</button>
                        </li>
                    ))}
                </ul>
                <h3>Total Amount: ${totalAmount}</h3>
                <button type='button' onClick={generateInvoice}>Generate Invoice PDF</button>
            </form>

            {/* Invoice Preview */}
            <div id='invoice'>
                    <h1>Invoice</h1>
                    <p>Patient Name: {patientName}</p>
                    <table>
                        <thead>
                            <tr>
                                <th>Service</th>
                                <th>Description</th>
                                <th>Quantity</th>
                                <th>Price</th>
                            </tr> 
                        </thead>                        
                        <tbody>
                            {selectedServices.map((service, index) => (
                            <tr key = {index}>
                                <td>{service.name}</td>
                                <td>{service.description}</td>
                                <td>{service.quantity}</td>
                                <td>{service.price}</td>                            
                            </tr>
                            ))}  
                        </tbody>                      
                    </table>
                    <h3> Total: ${totalAmount}</h3>
            </div>

        </div>
    )
};

export default CreateInvoice;
